const data = $input.first().json;
const bindings = (data && data.results && data.results.bindings) ? data.results.bindings : [];
console.log('Wikidata [Countries]: ' + bindings.length + ' rows');

const results = [];
for (const row of bindings) {
  try {
    const fn = (row) => {
      const b = row;
const name = b.itemLabel?.value;
if (!name || name.startsWith('Q')) return null;
return {
  name,
  type: 'country',
  properties: {
    iso_code: b.isoCode?.value || '',
    capital: b.capitalLabel?.value || '',
    population: b.population?.value || '',
    wikidata_qid: b.item?.value?.replace('http://www.wikidata.org/entity/', '') || ''
  },
  relationships: [],
  source: 'wikidata',
  confidence: 0.99,
  causal_weight: 0.5,
  mechanism: 'official_registry'
};
    };
    const entity = fn(row);
    if (!entity || !entity.name) continue;
    results.push({ json: entity });
  } catch(e) {
    // skip bad rows
  }
}

return results.length > 0
  ? results
  : [{ json: { name: 'empty', type: 'political_event', source: 'wikidata', properties: {}, relationships: [], confidence: 0, causal_weight: 0, mechanism: 'none' } }];

