const items = $input.all();
const BATCH_SIZE = 25;
const batches = [];
const valid = items.filter(i => i.json && typeof i.json === 'object' && i.json.name && i.json.name !== 'empty');
for (let i = 0; i < valid.length; i += BATCH_SIZE) {
  batches.push({ json: { batch: valid.slice(i, i + BATCH_SIZE).map(x => x.json) } });
}
return batches.length > 0 ? batches : [{ json: { batch: [] } }];
